import hashlib

def rainbow_table(passwords):
    table = []
    for password in passwords:
        hash = hashlib.md5(password.encode()).hexdigest()
        table.append((password, hash))
    return table

def rainbow_attack(table, target_hash):
    for password, hash in table:
        if hash == target_hash:
            return password
    return None

table = rainbow_table(passwords)
password = rainbow_attack(table, target_hash)

